import { useEffect, useState } from 'react'
import './App.css'

const API_BASE = import.meta.env.VITE_API_BASE ?? 'http://localhost:8000'

type HelloResponse = {
  message: string
  phase: string
}

type FetchState =
  | { kind: 'loading' }
  | { kind: 'ok'; data: HelloResponse }
  | { kind: 'error'; error: string }

function App() {
  const [state, setState] = useState<FetchState>({ kind: 'loading' })

  useEffect(() => {
    const controller = new AbortController()
    fetch(`${API_BASE}/api/hello`, { signal: controller.signal })
      .then(async (response) => {
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}`)
        }
        const data = (await response.json()) as HelloResponse
        setState({ kind: 'ok', data })
      })
      .catch((err: unknown) => {
        if (err instanceof DOMException && err.name === 'AbortError') return
        const message = err instanceof Error ? err.message : String(err)
        setState({ kind: 'error', error: message })
      })
    return () => controller.abort()
  }, [])

  return (
    <main className="hello-world">
      <h1>claim-evaluator-bot</h1>
      <p className="subtitle">Phase 04 scaffolding — frontend ↔ backend handshake</p>

      {state.kind === 'loading' && <p className="status">Calling backend…</p>}

      {state.kind === 'error' && (
        <p className="status error">
          Backend call failed: <code>{state.error}</code>
          <br />
          Is <code>uvicorn app.main:app --reload</code> running on{' '}
          <code>{API_BASE}</code>?
        </p>
      )}

      {state.kind === 'ok' && (
        <div className="status ok">
          <p>{state.data.message}</p>
          <p>
            Phase reported by API: <code>{state.data.phase}</code>
          </p>
        </div>
      )}
    </main>
  )
}

export default App

.hello-world {
  max-width: 640px;
  margin: 4rem auto;
  padding: 2rem;
  text-align: center;
}

.hello-world h1 {
  margin-bottom: 0.25rem;
  font-size: 2rem;
}

.hello-world .subtitle {
  color: var(--text-muted, #888);
  margin-top: 0;
  margin-bottom: 2rem;
  font-size: 0.9rem;
}

.hello-world .status {
  padding: 1rem 1.25rem;
  border-radius: 8px;
  border: 1px solid var(--border, #ddd);
  background: var(--card-bg, transparent);
}

.hello-world .status.ok {
  border-color: #2e7d32;
}

.hello-world .status.error {
  border-color: #c62828;
  color: #c62828;
  text-align: left;
}

.hello-world code {
  background: rgba(127, 127, 127, 0.15);
  padding: 0.1rem 0.35rem;
  border-radius: 4px;
  font-size: 0.9em;
}
